function getToken(){return localStorage.getItem("token")}const API={async request(t,e,r){const s={method:t,headers:{"Content-Type":"application/json"}},n=getToken();n&&(s.headers.Authorization=`Bearer ${n}`),r&&(s.body=JSON.stringify(r));const o=await fetch(`/api${e}`,s);if(!o.ok){const t=await o.json().catch(()=>({detail:o.statusText}));throw 401===o.status&&(localStorage.removeItem("token"),localStorage.removeItem("user"),window.location.hash="#/login"),new Error(t.detail||`Error ${o.status}`)}return o.json()},get(t){return this.request("GET",t)},post(t,e){return this.request("POST",t,e)},put(t,e){return this.request("PUT",t,e)},del(t){return this.request("DELETE",t)},login(t){return this.post("/auth/login",t)},register(t){return this.post("/auth/register",t)},me(){return this.get("/auth/me")},logout(){return this.post("/auth/logout")},listarClientes(){return this.get("/clientes")},crearCliente(t){return this.post("/clientes",t)},actualizarCliente(t,e){return this.put(`/clientes/${t}`,e)},eliminarCliente(t){return this.del(`/clientes/${t}`)}};